+enum MessageStepKind {
+    Send,
+    Receive,
+}
+
+impl MessageStepKind {
+    fn expectation(self, message: MessageType) -> ConformanceExpectation {
+        match self {
+            Self::Send => ConformanceExpectation::Send { message },
+            Self::Receive => ConformanceExpectation::Receive { message },
+        }
+    }
+}
